onOptionChange:
{{
(async () => {

  const typ = Number(RadioGroupWyszukaj.selectedOptionValue);
  const wartosci = SelectWyszukaj.selectedOptionValues || [];

  // Jeżeli nic nie wybrano - pokaż pełną listę ekspertów
  if (wartosci.length === 0) {

    await eksperciWykaz.run();

    return;

  }

  // Wyszukiwanie po dziedzinach
  if (typ === 1) {

    return Promise.all([
      eksperciDziedziny.run(),
      dziedzinyZKategoriami.run()
    ]);

  }

  // Wyszukiwanie po kategoriach
  if (typ === 2) {

    return Promise.all([
      eksperciKategorie.run(),
      kategorieZDziedzinami.run()
    ]);

  }

  // Wyszukiwanie po obszarach
  if (typ === 3) {

    return eksperciObszary.run();

  }

})();
}}

sourceData:
{{
  RadioGroupWyszukaj.selectedOptionValue == 1
    ? (getDziedziny.data || []).map(row => ({
        label: row.nazwa,
        value: String(row.id)
      }))
    : RadioGroupWyszukaj.selectedOptionValue == 2
      ? (getKategorie.data || []).map(row => ({
          label: row.id + " - " + row.nazwa_kategorie,
          value: String(row.id)
        }))
      : RadioGroupWyszukaj.selectedOptionValue == 3
        ? (getObszary.data || []).map(row => ({
            label: row.symbol_ob + " - " + row.nazwa_ob,
            value: String(row.id)
          }))
        : []
}}
